import React, { useId } from 'react';
import { Card, CardContent, Box, Typography, Stack } from '@mui/material';
import { ResponsiveChartContainer, LinePlot, ChartsXAxis, ChartsYAxis, ChartsClipPath } from '@mui/x-charts';
import response from './response.json';

interface WindData {
  location: string;
  current: {
    windSpeed: number;
    gustSpeed: number;
    direction: string;
  };
  hourlyTrend: {
    hour: string;
    windSpeed: number;
  }[];
  windTrend: number[];
}

export default function Widget() {
  const windData = response.data as WindData;
  const clipPathId = useId();

  return (
    <Card
      sx={{
        width: 'fit-content',
        minWidth: 350,
        maxWidth: 500,
        bgcolor: '#000000',
        color: '#FFFFFF',
      }}
      elevation={2}
    >
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="body2" color="text.secondary">
              {windData.location}
            </Typography>
            <Typography variant="h3" fontWeight={300} sx={{ my: 0.5, color: '#FFFFFF' }}>
              {windData.current.windSpeed} mph
            </Typography>
            <Typography variant="body2" sx={{ color: '#FFC107' }}>
              Gust: {windData.current.gustSpeed} mph, Direction: {windData.current.direction}
            </Typography>
          </Box>

          <Box sx={{ width: '100%', height: 200 }}>
            <ResponsiveChartContainer
              series={[
                {
                  type: 'line',
                  data: windData.hourlyTrend.map((trend) => trend.windSpeed),
                  color: '#FFC107',
                  label: 'Wind Speed',
                  curve: 'natural',
                },
              ]}
              xAxis={[
                {
                  scaleType: 'band',
                  data: windData.hourlyTrend.map((trend) => trend.hour),
                  id: 'hours',
                },
              ]}
              yAxis={[{ id: 'windSpeed' }]}
            >
              <g clipPath={`url(#${clipPathId})`}>
                <LinePlot />
              </g>
              <ChartsXAxis
                axisId="hours"
                tickLabelStyle={{ fontSize: 10, fill: '#FFFFFF' }}
              />
              <ChartsYAxis
                axisId="windSpeed"
                tickLabelStyle={{ fontSize: 10, fill: '#FFFFFF' }}
              />
              <ChartsClipPath id={clipPathId} />
            </ResponsiveChartContainer>
          </Box>
        </Stack>
      </CardContent>
    </Card>
  );
}
